  it 'error_handling_invalid_syntax: Parsing invalid syntax should produce a tree with error nodes.' do
    result = TreeSitterLanguagePack.process('function function function @@@ %%%', { 'language' => 'javascript' })

    expect(result).not_to be_nil
  end

  it 'error_handling_unknown_language: Loading a nonexistent language should produce an error.' do
    expect {
      TreeSitterLanguagePack.process('', { 'language' => 'nonexistent_xyz' })
    }.to raise_error(RuntimeError)
  end

  it 'error_process_empty_source: Process empty source code succeeds with zero metrics' do
    result = TreeSitterLanguagePack.process('', { 'language' => 'python' })
    expect(result.metrics.total_lines).to eq(0)

  end

  it 'parse_empty_language: process() returns error with empty language name' do
    expect {
      TreeSitterLanguagePack.process('x = 1', { 'language' => '' })
    }.to raise_error(RuntimeError)
  end

  it 'process_unknown_language: process() returns error when config language is unknown' do
    expect {
      TreeSitterLanguagePack.process('x = 1', { 'language' => 'nonexistent_xyz' })
    }.to raise_error(RuntimeError)
  end
end
